-- ----------------------------------------------------------------------------
-- vw_users: People who wind timers.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_users WITH (security_invoker = ON) AS
SELECT
  t.user_id,                                                                    -- Primary key.
  t.display_name,                                                               -- Human name.
  calc_users_wind_count(t.user_id) AS wind_count,                               -- Total wind actions performed by this user.
  calc_users_cook_count(t.user_id) AS cook_count,                               -- Total cooks this user has prepared today.
  calc_users_completed_cook_count(t.user_id) AS completed_cook_count,           -- Cooks this user has prepared that have finished (their timer has rung).
  calc_users_activity_level(t.user_id) AS activity_level,                       -- Fuzzy take on how active this user is today: idle if no winds, casual for one or two, busy for three or more.
  calc_users_total_recipe_minutes_attempted(t.user_id) AS total_recipe_minutes_attempted,-- Sum of recommended-minutes across recipes this user has cooked today. Zig-zags User -> Cook -> Recipe.RecommendedMinutes.
  calc_users_avg_recipe_minutes_attempted(t.user_id) AS avg_recipe_minutes_attempted,-- Mean recommended-minutes across this user's cooks today. Zig-zags User -> Cook -> Recipe.RecommendedMinutes.
  calc_users_cooking_style(t.user_id) AS cooking_style                          -- Fuzzy verdict on this user's day, off the zig-zag aggregate AvgRecipeMinutesAttempted: 'snacking' under 10 min average, 'short-order' under 30, 'slow-cooking' beyond.
FROM users t;

-- ----------------------------------------------------------------------------
-- vw_timers: Top-level timer assembly. Holds the raw mechanical parameters and the headline runtime DAG: stored torque, remaining minutes, wind state, and whether the bell has rung.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_timers WITH (security_invoker = ON) AS
SELECT
  t.timer_id,                                                                   -- Primary key.
  t.label,                                                                      -- User-facing label.
  t.wind_angle_degrees,                                                         -- Current angular position of the winding knob, 0..MaxWindDegrees.
  t.max_wind_degrees,                                                           -- Full-wind knob travel; 360 deg = 60 min on a standard dial.
  t.max_spring_torque_nm,                                                       -- Mainspring torque at full wind, newton-meters.
  t.escapement_base_hz,                                                         -- Pallet oscillation frequency in §4.
  calc_timers_wind_fraction(t.timer_id) AS wind_fraction,                       -- Fraction of full wind currently stored.
  calc_timers_stored_torque_nm(t.timer_id) AS stored_torque_nm,                 -- Torque currently stored in the mainspring (§2).
  calc_timers_remaining_minutes(t.timer_id) AS remaining_minutes,               -- Minutes left until the cam trips §5.
  calc_timers_wind_state(t.timer_id) AS wind_state,                             -- Coarse state: Unwound, Partial, or Full.
  calc_timers_is_armed(t.timer_id) AS is_armed,                                 -- True while the mainspring still holds energy.
  calc_timers_has_rung(t.timer_id) AS has_rung,                                 -- True once §5 has fired.
  calc_timers_tick_count(t.timer_id) AS tick_count,                             -- Total escapement ticks recorded for this timer.
  calc_timers_ring_count(t.timer_id) AS ring_count,                             -- Total ding events recorded for this timer.
  calc_timers_cook_count(t.timer_id) AS cook_count,                             -- Number of cooks currently or recently timed on this timer.
  calc_timers_total_recipe_minutes_used(t.timer_id) AS total_recipe_minutes_used,-- Sum of recommended minutes across recipes the cooks on this timer are following. Zig-zags through Cook to Recipe.
  calc_timers_avg_recipe_minutes_used(t.timer_id) AS avg_recipe_minutes_used,   -- Average recommended-minutes across the recipes any cook on this timer is following. Goes Timer -> Cook (rollup) -> Recipe (the underlying lookup).
  calc_timers_wind_duration_minutes(t.timer_id) AS wind_duration_minutes,       -- How many minutes one full wind buys on this timer. Derived from MaxWindDegrees at 6 deg per minute.
  calc_timers_expected_ticks_per_minute(t.timer_id) AS expected_ticks_per_minute,-- Escapement ticks expected per minute on this timer.
  calc_timers_expected_total_ticks(t.timer_id) AS expected_total_ticks,         -- Ticks expected across a full wind, end to end.
  calc_timers_ticks_elapsed_expected(t.timer_id) AS ticks_elapsed_expected,     -- Ticks that should have occurred so far on this timer based on how much the spring has unwound.
  calc_timers_tick_efficiency_percent(t.timer_id) AS tick_efficiency_percent,   -- Observed ticks divided by expected ticks so far, as a percentage. A timer that has just been wound returns 100 since no ticks were expected yet.
  calc_timers_has_sparse_tick_record(t.timer_id) AS has_sparse_tick_record,     -- True when the recorded tick count is well below what should have happened by now.
  calc_timers_mechanical_phase(t.timer_id) AS mechanical_phase                  -- Fuzzy lifecycle phase. A timer is freshly-wound if barely any of its wind has been spent, mid-run if it is well into its travel, nearly-done if it is almost out of energy, and rung once it has fired.
FROM timers t;

-- ----------------------------------------------------------------------------
-- vw_cases: The outer housing of a timer. The bell is mounted on top of the case.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_cases WITH (security_invoker = ON) AS
SELECT
  t.case_id,                                                                    -- Primary key.
  t.houses_timer,                                                               -- Parent timer.
  t.material                                                                    -- Case material.
FROM cases t;

-- ----------------------------------------------------------------------------
-- vw_bells: The bell mounted on top of the case. Struck by the hammer striker when §5 fires.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_bells WITH (security_invoker = ON) AS
SELECT
  t.bell_id,                                                                    -- Primary key.
  t.mounted_on_case,                                                            -- Case the bell sits on.
  t.diameter_mm,                                                                -- Bell diameter, mm.
  t.tone_hz,                                                                    -- Dominant tone, Hz.
  calc_bells_times_rung(t.bell_id) AS times_rung,                               -- Number of ding events for this bell.
  calc_bells_has_ever_rung(t.bell_id) AS has_ever_rung                          -- True if at least one ding has been recorded.
FROM bells t;

-- ----------------------------------------------------------------------------
-- vw_winding_knobs: §1 — the dial on the front. Shaft is fixed to the mainspring arbor. Rim carries a printed scale 0..60 read against a fixed pointer on the case.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_winding_knobs WITH (security_invoker = ON) AS
SELECT
  t.winding_knob_id,                                                            -- Primary key.
  t.fixed_to_timer,                                                             -- Parent timer.
  t.scale_min,                                                                  -- Lower bound of the printed scale.
  t.scale_max,                                                                  -- Upper bound of the printed scale.
  t.wind_direction,                                                             -- Clockwise or counter-clockwise.
  t.shaft_diameter_mm,                                                          -- Diameter of the knob shaft.
  t.pointer_fixed,                                                              -- True if the case pointer is fixed (it always is on this design).
  calc_winding_knobs_timer_wind_angle(t.winding_knob_id) AS timer_wind_angle,   -- Parent timer's current wind angle.
  calc_winding_knobs_timer_max_wind(t.winding_knob_id) AS timer_max_wind,       -- Parent timer's max wind angle.
  calc_winding_knobs_scale_reading(t.winding_knob_id) AS scale_reading          -- Number the printed scale currently shows against the pointer.
FROM winding_knobs t;

-- ----------------------------------------------------------------------------
-- vw_arbors: The shaft driven by the mainspring. Connects §1 (knob shaft) to §2 (mainspring), and carries the §5 cam.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_arbors WITH (security_invoker = ON) AS
SELECT
  t.arbor_id,                                                                   -- Primary key.
  t.in_timer,                                                                   -- Parent timer.
  t.diameter_mm                                                                 -- Arbor diameter.
FROM arbors t;

-- ----------------------------------------------------------------------------
-- vw_mainsprings: §2 — flat coiled steel spring in a drum. Inner end anchors to the arbor; outer end anchors to the case.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_mainsprings WITH (security_invoker = ON) AS
SELECT
  t.mainspring_id,                                                              -- Primary key.
  t.wrapped_on_arbor,                                                           -- Arbor this mainspring drives.
  t.drum_diameter_mm,                                                           -- Diameter of the spring drum.
  t.material,                                                                   -- Spring material.
  t.inner_end_anchor,                                                           -- Where the inner end anchors (always Arbor).
  t.outer_end_anchor                                                            -- Where the outer end anchors (always Case).
FROM mainsprings t;

-- ----------------------------------------------------------------------------
-- vw_gear_trains: §3 — the three-gear stack between mainspring arbor and escapement. Carries the output shaft that drives the dial pointer.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_gear_trains WITH (security_invoker = ON) AS
SELECT
  t.gear_train_id,                                                              -- Primary key.
  t.in_timer,                                                                   -- Parent timer.
  t.reduction_ratio,                                                            -- Total speed-up from arbor to escapement.
  calc_gear_trains_timer_escapement_hz(t.gear_train_id) AS timer_escapement_hz, -- Parent timer's escapement frequency.
  calc_gear_trains_output_shaft_rpm(t.gear_train_id) AS output_shaft_rpm,       -- Speed of the output shaft (the one carrying the dial pointer).
  calc_gear_trains_gear_count(t.gear_train_id) AS gear_count,                   -- Number of gears in this train. Always 3 on this design.
  calc_gear_trains_total_teeth(t.gear_train_id) AS total_teeth,                 -- Sum of tooth counts across the three gears.
  calc_gear_trains_average_tooth_count(t.gear_train_id) AS average_tooth_count  -- Mean tooth count across the gears in this train.
FROM gear_trains t;

-- ----------------------------------------------------------------------------
-- vw_gears: Individual gears in a gear train. Each has a tooth count and a position in the chain (1, 2, or 3).
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_gears WITH (security_invoker = ON) AS
SELECT
  t.gear_id,                                                                    -- Primary key.
  t.in_gear_train,                                                              -- Parent gear train.
  t.position_in_chain,                                                          -- 1, 2, or 3 — arbor side to escapement side.
  t.tooth_count,                                                                -- Number of teeth on this gear.
  calc_gears_is_first_in_chain(t.gear_id) AS is_first_in_chain,                 -- True for the gear nearest the arbor.
  calc_gears_is_last_in_chain(t.gear_id) AS is_last_in_chain,                   -- True for the gear nearest the escapement.
  calc_gears_size_class(t.gear_id) AS size_class,                               -- Fuzzy size based on tooth count: large 40+, medium 25-39, small under 25.
  calc_gears_on_timer(t.gear_id) AS on_timer                                    -- Timer the gear's gear-train belongs to (chained lookup through GearTrains).
FROM gears t;

-- ----------------------------------------------------------------------------
-- vw_output_shafts: The shaft at the end of the gear train. Carries the dial pointer.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_output_shafts WITH (security_invoker = ON) AS
SELECT
  t.output_shaft_id,                                                            -- Primary key.
  t.in_gear_train,                                                              -- Parent gear train.
  calc_output_shafts_current_rpm(t.output_shaft_id) AS current_rpm              -- Inherits the gear train's output RPM.
FROM output_shafts t;

-- ----------------------------------------------------------------------------
-- vw_dial_pointers: Pointer mounted on the output shaft. Reads against the printed scale on the knob rim.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_dial_pointers WITH (security_invoker = ON) AS
SELECT
  t.dial_pointer_id,                                                            -- Primary key.
  t.on_output_shaft,                                                            -- Shaft this pointer is mounted on.
  t.length_mm                                                                   -- Pointer length.
FROM dial_pointers t;

-- ----------------------------------------------------------------------------
-- vw_escapements: §4 — escapement assembly: toothed wheel plus two-pronged pallet plus hairspring. Defines the time base.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_escapements WITH (security_invoker = ON) AS
SELECT
  t.escapement_id,                                                              -- Primary key.
  t.in_timer,                                                                   -- Parent timer.
  calc_escapements_tick_count(t.escapement_id) AS tick_count,                   -- Ticks recorded at this escapement.
  calc_escapements_has_ticked(t.escapement_id) AS has_ticked                    -- True if this escapement has recorded at least one tick.
FROM escapements t;

-- ----------------------------------------------------------------------------
-- vw_escapement_wheels: The toothed wheel of the escapement. Each pallet rock releases exactly one tooth.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_escapement_wheels WITH (security_invoker = ON) AS
SELECT
  t.escapement_wheel_id,                                                        -- Primary key.
  t.in_escapement,                                                              -- Parent escapement.
  t.tooth_count                                                                 -- Number of teeth around the wheel.
FROM escapement_wheels t;

-- ----------------------------------------------------------------------------
-- vw_pallets: Pivoting piece sitting across the escapement-wheel teeth. Two prongs (the README's 'two-pronged pallet'). Rocking is set by pallet mass plus the hairspring.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_pallets WITH (security_invoker = ON) AS
SELECT
  t.pallet_id,                                                                  -- Primary key.
  t.in_escapement,                                                              -- Parent escapement.
  t.prong_count,                                                                -- Number of prongs. Always 2 on this design.
  t.mass_grams                                                                  -- Pallet mass. Co-determines rocking rate.
FROM pallets t;

-- ----------------------------------------------------------------------------
-- vw_hairsprings: Tiny coiled spring attached to the pallet. Sets the pallet's rocking rate together with pallet mass.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_hairsprings WITH (security_invoker = ON) AS
SELECT
  t.hairspring_id,                                                              -- Primary key.
  t.attached_to_pallet,                                                         -- Parent pallet.
  t.stiffness_nm_per_rad                                                        -- Torsional stiffness.
FROM hairsprings t;

-- ----------------------------------------------------------------------------
-- vw_cams: Profile on the arbor of §2. Its notch aligns with the hammer catch at the zero position; that alignment is what trips §5.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_cams WITH (security_invoker = ON) AS
SELECT
  t.cam_id,                                                                     -- Primary key.
  t.on_arbor,                                                                   -- Arbor this cam rides on.
  t.notch_angle_deg                                                             -- Arbor angle at which the notch aligns with the catch.
FROM cams t;

-- ----------------------------------------------------------------------------
-- vw_bell_hammers: §5 — spring-loaded arm with a steel striker, held back by the hammer catch. When the cam notch reaches the catch, the catch releases and the arm's own spring snaps the striker against the bell.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_bell_hammers WITH (security_invoker = ON) AS
SELECT
  t.bell_hammer_id,                                                             -- Primary key.
  t.in_timer,                                                                   -- Parent timer.
  t.arm_torque_nm,                                                              -- Spring torque stored in the hammer arm.
  calc_bell_hammers_timer_has_rung(t.bell_hammer_id) AS timer_has_rung,         -- Whether the parent timer has rung.
  calc_bell_hammers_release_state(t.bell_hammer_id) AS release_state            -- Held while the cam still restrains the catch; Released once the timer has rung.
FROM bell_hammers t;

-- ----------------------------------------------------------------------------
-- vw_hammer_arms: The spring-loaded arm of the bell hammer. Carries the striker at its tip.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_hammer_arms WITH (security_invoker = ON) AS
SELECT
  t.hammer_arm_id,                                                              -- Primary key.
  t.of_bell_hammer,                                                             -- Parent bell hammer.
  t.length_mm                                                                   -- Arm length.
FROM hammer_arms t;

-- ----------------------------------------------------------------------------
-- vw_strikers: The small steel head at the tip of the hammer arm. Whatever actually contacts the bell.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_strikers WITH (security_invoker = ON) AS
SELECT
  t.striker_id,                                                                 -- Primary key.
  t.on_arm,                                                                     -- Hammer arm this striker is mounted on.
  t.material                                                                    -- Striker material.
FROM strikers t;

-- ----------------------------------------------------------------------------
-- vw_hammer_catches: Catch that holds the hammer back until the cam notch aligns. Once released, the arm spring snaps the striker against the bell.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_hammer_catches WITH (security_invoker = ON) AS
SELECT
  t.hammer_catch_id,                                                            -- Primary key.
  t.of_bell_hammer,                                                             -- Parent bell hammer.
  t.engaged_with_cam,                                                           -- Cam this catch rides against.
  calc_hammer_catches_hammer_release_state(t.hammer_catch_id) AS hammer_release_state,-- Inherits parent hammer's release state.
  calc_hammer_catches_is_engaged(t.hammer_catch_id) AS is_engaged               -- True while the catch still restrains the hammer.
FROM hammer_catches t;

-- ----------------------------------------------------------------------------
-- vw_wind_actions: Event: a user rotates the winding knob to a target angle at a point in time. The README's §1 input event.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_wind_actions WITH (security_invoker = ON) AS
SELECT
  t.wind_action_id,                                                             -- Primary key.
  t.performed_by,                                                               -- Acting user.
  t.turned_knob,                                                                -- Knob that was turned.
  t.target_angle_deg,                                                           -- Angle wound to, in degrees.
  t.occurred_at,                                                                -- When the wind happened.
  calc_wind_actions_applied_to_timer(t.wind_action_id) AS applied_to_timer,     -- Timer the turned knob is fixed to.
  calc_wind_actions_resulted_in_ring(t.wind_action_id) AS resulted_in_ring      -- True if the timer this wind action wound has since rung.
FROM wind_actions t;

-- ----------------------------------------------------------------------------
-- vw_tick_events: Event: the escapement releases one tooth — one 'tick' from the README.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_tick_events WITH (security_invoker = ON) AS
SELECT
  t.tick_event_id,                                                              -- Primary key.
  t.happened_on_timer,                                                          -- Parent timer.
  t.at_escapement,                                                              -- Escapement that ticked.
  t.occurred_at,                                                                -- Tick timestamp.
  calc_tick_events_timer_label(t.tick_event_id) AS timer_label,                 -- Parent timer's label.
  calc_tick_events_on_timer_that_has_rung(t.tick_event_id) AS on_timer_that_has_rung,-- Whether the parent timer has rung.
  calc_tick_events_on_timer_in_phase(t.tick_event_id) AS on_timer_in_phase      -- Parent timer's current mechanical phase.
FROM tick_events t;

-- ----------------------------------------------------------------------------
-- vw_ring_events: Event: the bell hammer strikes the bell — the README's 'ding'. Recorded once per fired §5.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_ring_events WITH (security_invoker = ON) AS
SELECT
  t.ring_event_id,                                                              -- Primary key.
  t.happened_on_timer,                                                          -- Parent timer.
  t.struck,                                                                     -- Bell that was struck.
  t.occurred_at                                                                 -- Ring timestamp.
FROM ring_events t;

-- ----------------------------------------------------------------------------
-- vw_cooks: A dish being timed on a timer. Each cook started at the moment a user wound the timer; its status mirrors the timer's lifecycle.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_cooks WITH (security_invoker = ON) AS
SELECT
  t.cook_id,                                                                    -- Primary key.
  t.on_timer,                                                                   -- Timer being used.
  t.prepared_by,                                                                -- User preparing the dish.
  t.dish_name,                                                                  -- Name of the dish.
  t.started_at,                                                                 -- When the dish was started — i.e. when the timer was wound.
  calc_cooks_timer_has_rung(t.cook_id) AS timer_has_rung,                       -- Whether the cook's timer has rung yet.
  calc_cooks_timer_is_armed(t.cook_id) AS timer_is_armed,                       -- Whether the cook's timer is still armed.
  calc_cooks_timer_remaining_min(t.cook_id) AS timer_remaining_min,             -- Minutes the cook's timer has left.
  calc_cooks_status(t.cook_id) AS status,                                       -- Done if the timer has rung, Cooking if it is still armed, otherwise Pending.
  t.follows_recipe,                                                             -- Recipe being followed.
  calc_cooks_recommended_minutes(t.cook_id) AS recommended_minutes,             -- Minutes the recipe calls for.
  calc_cooks_timer_wind_duration(t.cook_id) AS timer_wind_duration,             -- Maximum minutes the chosen timer can run.
  calc_cooks_timer_can_cover_recipe(t.cook_id) AS timer_can_cover_recipe,       -- True if the chosen timer can run for at least as long as the recipe calls for.
  calc_cooks_suitability_verdict(t.cook_id) AS suitability_verdict,             -- Fuzzy verdict on the cook's choice of timer: insufficient if the timer is too short for the recipe, overkill if it can run more than three times as long as needed, otherwise appropriate.
  calc_cooks_prepared_by_name(t.cook_id) AS prepared_by_name,                   -- Display name of the user preparing this cook.
  calc_cooks_prepared_by_activity_level(t.cook_id) AS prepared_by_activity_level,-- Activity-level verdict on the user preparing this cook (chained lookup through Users).
  calc_cooks_recipe_duration_category(t.cook_id) AS recipe_duration_category,   -- Duration-category of the recipe being followed (chained lookup through Recipes).
  calc_cooks_recipe_temp_profile(t.cook_id) AS recipe_temp_profile,             -- Cooking-temp profile of the recipe (chained lookup through Recipes).
  calc_cooks_timer_mechanical_phase(t.cook_id) AS timer_mechanical_phase        -- Mechanical phase of the timer this cook is on (chained lookup through Timers).
FROM cooks t;

-- ----------------------------------------------------------------------------
-- vw_recipes: Cooking recipes a cook can follow. Each names a dish and the minutes it should run.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_recipes WITH (security_invoker = ON) AS
SELECT
  t.recipe_id,                                                                  -- Primary key.
  t.dish_name,                                                                  -- Name of the dish.
  t.recommended_minutes,                                                        -- Recommended cook time, in minutes.
  t.ideal_temperature_c,                                                        -- Recommended cooking temperature, in degrees Celsius.
  calc_recipes_times_used_today(t.recipe_id) AS times_used_today,               -- Cooks following this recipe today.
  calc_recipes_duration_category(t.recipe_id) AS duration_category,             -- A loose verbal classification of how long this recipe takes: quick under 5 min, short under 15, medium under 45, long beyond that.
  calc_recipes_cooking_temp_profile(t.recipe_id) AS cooking_temp_profile,       -- Loose verbal classification of cooking temperature: boiling, hot oven, warm oven, or low.
  calc_recipes_avg_timer_capacity(t.recipe_id) AS avg_timer_capacity,           -- Average wind-duration of the timers cooks have used for this recipe. Zig-zags Recipe -> Cook -> Timer.WindDurationMinutes.
  calc_recipes_total_timer_capacity(t.recipe_id) AS total_timer_capacity,       -- Sum of timer wind-durations allocated to this recipe today. Zig-zags Recipe -> Cook -> Timer.WindDurationMinutes.
  calc_recipes_assignment_verdict(t.recipe_id) AS assignment_verdict            -- Fuzzy verdict on how well this recipe's actual timer assignments match what it needs. Drives off the zig-zag aggregate AvgTimerCapacity vs the recipe's own RecommendedMinutes.
FROM recipes t;

-- ----------------------------------------------------------------------------
-- vw_kitchens: A kitchen, top of the rollup tree. Aggregates everything below it.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_kitchens WITH (security_invoker = ON) AS
SELECT
  t.kitchen_id,                                                                 -- Primary key.
  t.display_name,                                                               -- Human name.
  calc_kitchens_total_timers(t.kitchen_id) AS total_timers,                     -- Count of timers in the world.
  calc_kitchens_total_cases(t.kitchen_id) AS total_cases,                       -- Count of cases.
  calc_kitchens_total_bells(t.kitchen_id) AS total_bells,                       -- Count of bells.
  calc_kitchens_total_users(t.kitchen_id) AS total_users,                       -- Count of users.
  calc_kitchens_total_cooks(t.kitchen_id) AS total_cooks,                       -- Count of cooks today.
  calc_kitchens_total_recipes(t.kitchen_id) AS total_recipes,                   -- Count of recipes.
  calc_kitchens_total_wind_actions(t.kitchen_id) AS total_wind_actions,         -- Wind actions today.
  calc_kitchens_total_tick_events(t.kitchen_id) AS total_tick_events,           -- Tick events recorded today.
  calc_kitchens_total_ring_events(t.kitchen_id) AS total_ring_events,           -- Ring events recorded today.
  calc_kitchens_timers_freshly_wound(t.kitchen_id) AS timers_freshly_wound,     -- Timers currently freshly-wound.
  calc_kitchens_timers_mid_run(t.kitchen_id) AS timers_mid_run,                 -- Timers currently mid-run.
  calc_kitchens_timers_nearly_done(t.kitchen_id) AS timers_nearly_done,         -- Timers currently nearly-done.
  calc_kitchens_timers_rung(t.kitchen_id) AS timers_rung,                       -- Timers that have rung.
  calc_kitchens_cooks_done(t.kitchen_id) AS cooks_done,                         -- Cooks whose status is Done.
  calc_kitchens_cooks_cooking(t.kitchen_id) AS cooks_cooking,                   -- Cooks whose status is Cooking.
  calc_kitchens_recipes_unused(t.kitchen_id) AS recipes_unused,                 -- Recipes nobody cooked today.
  calc_kitchens_recipes_under_provisioned(t.kitchen_id) AS recipes_under_provisioned,-- Recipes whose chosen timer can't cover them.
  calc_kitchens_recipes_well_matched(t.kitchen_id) AS recipes_well_matched,     -- Recipes whose timer assignment was well-matched.
  calc_kitchens_busy_users(t.kitchen_id) AS busy_users,                         -- Users with activity-level busy.
  calc_kitchens_idle_users(t.kitchen_id) AS idle_users,                         -- Users with activity-level idle.
  calc_kitchens_total_recipe_minutes(t.kitchen_id) AS total_recipe_minutes,     -- Sum of recommended-minutes across all recipes.
  calc_kitchens_avg_recipe_minutes(t.kitchen_id) AS avg_recipe_minutes,         -- Mean recommended-minutes across all recipes.
  calc_kitchens_min_recipe_minutes(t.kitchen_id) AS min_recipe_minutes,         -- Shortest recipe in minutes.
  calc_kitchens_max_recipe_minutes(t.kitchen_id) AS max_recipe_minutes,         -- Longest recipe in minutes.
  calc_kitchens_has_any_timer_rung(t.kitchen_id) AS has_any_timer_rung,         -- True if any timer has rung today.
  calc_kitchens_has_misprovisioned_recipe(t.kitchen_id) AS has_misprovisioned_recipe,-- True if any recipe is currently under-provisioned.
  calc_kitchens_operational_status(t.kitchen_id) AS operational_status          -- Fuzzy overall status: 'quiet' if no cooks active, 'busy' if many, 'active' otherwise.
FROM kitchens t;

